-- RLS policies, helper functions, and auth bootstrap trigger for FridgeMind.
-- Hand-written (not generated by `prisma migrate diff`) since Prisma's schema has no
-- representation of RLS/functions/triggers — this is expected/normal for Prisma+Supabase.
--
-- Household/role rules implemented here follow CLAUDE.md §5 ("Роли в household"):
--   - Household-scoped access via a helper that resolves the caller's own household_id/role
--     from public.users, keyed by auth.uid() (avoids the recursive-RLS trap of a policy on
--     `users` subquerying `users` directly).
--   - recipes/recipe_steps/recipe_ingredients/meal_slots/menu_weeks/menu_days/menu_day_meals
--     writable only by ORGANIZER/EDITOR.
--   - pantry_items/shopping_list_items/shopping_list_item_meals writable by all roles.
--   - ingredients is a global catalog (no household_id) — readable/insertable by anyone
--     authenticated, grows organically.
--   - households/users role-management writes (renaming household, regenerating invite
--     code, changing another member's role, removing a member) restricted to ORGANIZER.

-- ============================================================================
-- Helper functions
-- ============================================================================

create or replace function public.current_household_id()
returns text
language sql
security definer
stable
set search_path = ''
as $$
  select household_id from public.users where id = auth.uid()::text
$$;

create or replace function public.current_household_role()
returns public.household_role
language sql
security definer
stable
set search_path = ''
as $$
  select role from public.users where id = auth.uid()::text
$$;

-- ============================================================================
-- households
-- ============================================================================

alter table public.households enable row level security;

create policy "households_select_own" on public.households for select to authenticated
  using ( id = public.current_household_id() );

create policy "households_update_organizer" on public.households for update to authenticated
  using ( id = public.current_household_id() and public.current_household_role() = 'ORGANIZER' )
  with check ( id = public.current_household_id() and public.current_household_role() = 'ORGANIZER' );

-- No INSERT policy: households are only ever created by handle_new_user (SECURITY DEFINER,
-- bypasses RLS as the function owner). No DELETE policy: household deletion is out of MVP scope.

-- ============================================================================
-- users
-- ============================================================================

alter table public.users enable row level security;

create policy "users_select_household" on public.users for select to authenticated
  using ( household_id = public.current_household_id() );

create policy "users_update_self" on public.users for update to authenticated
  using ( id = auth.uid()::text )
  with check ( id = auth.uid()::text );
-- Known limitation (documented, not solved at the RLS layer here): this is row-level, not
-- column-level, so a MEMBER could technically UPDATE their own role/household_id via a raw
-- request. Per CLAUDE.md §9 ("RLS-политики/server actions" — either is acceptable), the
-- column-level restriction is deferred to the server-action layer that already has role-check
-- TODOs in the API routes, rather than solved here.

create policy "users_update_by_organizer" on public.users for update to authenticated
  using ( household_id = public.current_household_id() and public.current_household_role() = 'ORGANIZER' )
  with check ( household_id = public.current_household_id() and public.current_household_role() = 'ORGANIZER' );

create policy "users_delete_self" on public.users for delete to authenticated
  using ( id = auth.uid()::text );
-- "At least one ORGANIZER must remain" (CLAUDE.md §5) is a cross-row business invariant that
-- RLS can't express — enforced in the future "leave household" server action, not here.

create policy "users_delete_by_organizer" on public.users for delete to authenticated
  using ( household_id = public.current_household_id() and public.current_household_role() = 'ORGANIZER' and id <> auth.uid()::text );

-- ============================================================================
-- ingredients (global catalog, no household_id — see CLAUDE.md §5)
-- ============================================================================

alter table public.ingredients enable row level security;

create policy "ingredients_select_authenticated" on public.ingredients for select to authenticated
  using ( true );

create policy "ingredients_insert_authenticated" on public.ingredients for insert to authenticated
  with check ( true );

-- No UPDATE/DELETE policy: catalog corrections are out of MVP scope (deny by default).

