create policy "recipes_insert_organizer_editor" on public.recipes for insert to authenticated
  with check ( household_id = public.current_household_id() and public.current_household_role() in ('ORGANIZER','EDITOR') );

create policy "recipes_update_organizer_editor" on public.recipes for update to authenticated
  using ( household_id = public.current_household_id() and public.current_household_role() in ('ORGANIZER','EDITOR') )
  with check ( household_id = public.current_household_id() and public.current_household_role() in ('ORGANIZER','EDITOR') );

create policy "recipes_delete_organizer_editor" on public.recipes for delete to authenticated
  using ( household_id = public.current_household_id() and public.current_household_role() in ('ORGANIZER','EDITOR') );

