    select 1 from public.recipes r
    where r.id = recipe_steps.recipe_id and r.household_id = public.current_household_id()
      and public.current_household_role() in ('ORGANIZER','EDITOR')
  ) );

create policy "recipe_steps_update_organizer_editor" on public.recipe_steps for update to authenticated
  using ( exists (
    select 1 from public.recipes r
    where r.id = recipe_steps.recipe_id and r.household_id = public.current_household_id()
      and public.current_household_role() in ('ORGANIZER','EDITOR')
  ) )
  with check ( exists (
    select 1 from public.recipes r
    where r.id = recipe_steps.recipe_id and r.household_id = public.current_household_id()
      and public.current_household_role() in ('ORGANIZER','EDITOR')
  ) );

create policy "recipe_steps_delete_organizer_editor" on public.recipe_steps for delete to authenticated
