-- ============================================================================
-- Grants (PostgREST needs both RLS policies AND a role-level GRANT)
-- ============================================================================

grant usage on schema public to authenticated;
grant select, insert, update, delete on all tables in schema public to authenticated;
grant execute on all functions in schema public to authenticated;

-- ============================================================================
-- handle_new_user: bootstraps households/users/meal_slots on auth.users signup
-- ============================================================================

create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_name text;
  v_invite_code text;
  v_household_id text;
  v_role public.household_role;
begin
  v_name := coalesce(new.raw_user_meta_data->>'name', split_part(new.email, '@', 1));
  v_invite_code := new.raw_user_meta_data->>'inviteCode';

  if v_invite_code is not null then
    select id into v_household_id from public.households where invite_code = v_invite_code;
  end if;

  if v_household_id is null then
    insert into public.households (id, invite_code, created_at, updated_at)
    values (extensions.gen_random_uuid()::text, extensions.gen_random_uuid()::text, now(), now())
    returning id into v_household_id;

    insert into public.meal_slots (id, household_id, name, "order", created_at) values
      (extensions.gen_random_uuid()::text, v_household_id, 'Завтрак', 0, now()),
      (extensions.gen_random_uuid()::text, v_household_id, 'Обед',    1, now()),
      (extensions.gen_random_uuid()::text, v_household_id, 'Ужин',   2, now());

    v_role := 'ORGANIZER';
  else
    v_role := 'MEMBER';
  end if;

  insert into public.users (id, email, name, household_id, role, created_at, updated_at)
  values (new.id::text, new.email, v_name, v_household_id, v_role, now(), now());

  return new;
end;
$$;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- Note: raw_user_meta_data is acceptable here only because it bootstraps membership at
-- signup time, not as an ongoing authorization source — every RLS policy above reads
-- public.users.role, never JWT claims. The "already in another household, replace" flow
-- (CLAUDE.md §6) applies to an already-authenticated user hitting an invite link, not a new
-- signup, and is a future server action/RPC, out of scope here.

-- ============================================================================
-- mark_meal_eaten: narrow RPC so MEMBER can mark a meal eaten without a broad UPDATE grant
-- ============================================================================

-- menu_day_meals otherwise follows the ORGANIZER/EDITOR-only write pattern, but CLAUDE.md §5
-- requires MEMBER be able to mark a meal eaten. Rather than loosening the general UPDATE
-- policy (which would also let MEMBER change recipe_id/servings/meal_slot_id), this RPC keeps
-- the blanket table policy strictly ORGANIZER/EDITOR at the cost of one extra function to
-- keep in sync with schema changes.
create or replace function public.mark_meal_eaten(p_menu_day_meal_id text, p_is_eaten boolean)
returns void
language plpgsql
security definer
set search_path = ''
as $$
begin
  update public.menu_day_meals m
  set is_eaten = p_is_eaten,
      eaten_at = case when p_is_eaten then now() else null end,
      eaten_by_user_id = case when p_is_eaten then auth.uid()::text else null end
  from public.menu_days d
  join public.menu_weeks w on w.id = d.menu_week_id
  where m.id = p_menu_day_meal_id
    and m.menu_day_id = d.id
    and w.household_id = public.current_household_id();
end;
$$;

grant execute on function public.mark_meal_eaten(text, boolean) to authenticated;
